// Descobre o tipo do arquivo (PDF x planilha) e mantém o binário para extração.
const item = $input.first();
const bin = (item.binary && item.binary.data) || {};
const name = (bin.fileName || '').toString().toLowerCase();
const mime = (bin.mimeType || '').toString().toLowerCase();
let kind = 'spreadsheet';
if (name.endsWith('.pdf') || mime.includes('pdf')) kind = 'pdf';
return [{ json: { kind, arquivo: bin.fileName || 'Relatório de Necessidades' }, binary: item.binary }];

// Normaliza linhas do Relatório de Necessidades e separa os metadados do upload.
// Aceita planilha (Excel/CSV) e PDF (parser best-effort). Risco/lead time fica no banco.
const meta = ($('Receive Report').first().json.body) || {};
const comp = (meta.competencia || '').toString().trim();
// '2026-06' (input type=month) -> primeiro dia do mês; senão null
const competencia = comp ? (comp.length === 7 ? comp + '-01' : comp) : null;
const items = $input.all();
const first = items[0] && items[0].json;
const isPdf = items.length === 1 && first && typeof first.text === 'string' && first.text.length > 40;
let rows = [];
if (isPdf) {
  // pdf-parse do n8n (v1.x) extrai numeros COLADOS (sem espaco) e o C/F no meio;
  // outras versoes separam por espaco. Este parser tolera os dois formatos.
  //   CODIGO - DESCRICAO+UND <n1..n9> C|F <n10>
  //   n9 = Necessidade final (liquida do ERP); n8 = Total Saidas (bruta);
  //   n1 = Ped. Compra; n10 (apos C/F) = Est. Disp + Alo (estoque atual).
  const UNITS = ['PC','UN','KG','M2','M3','MT','LT','CX','PR','PT','RL','CJ','GR','ML','BR','MM','CM','M'];
  const reNum = /-?\d{1,3}(?:\.\d{3})*,\d{4}/g;
  const reItem = /^(\S+)\s*-\s*(.*?,\d{4})\s*([CF])\s*(-?\d{1,3}(?:\.\d{3})*,\d{4})\s*$/;
  for (const raw of first.text.split(/\r?\n/)) {
    const line = (raw || '').trim();
    if (!line) continue;
    const m = line.match(reItem);
    if (!m) continue;
    const nums = (m[2].match(reNum) || []);
    if (nums.length < 2) continue;
    let descUnid = m[2].replace(reNum, '').trim();
    let unidade = '';
    for (const u of UNITS) {
      if (descUnid.toUpperCase().endsWith(u)) { unidade = u; descUnid = descUnid.slice(0, descUnid.length - u.length).trim(); break; }
    }
    rows.push({
      codigo: m[1].trim(),
      descricao: descUnid,
      unidade,
      grupo: m[3] === 'F' ? 'fabricado' : 'comprado',
      estoque_atual: m[4],
      pedido_aberto_qtd: nums[0] || '0',
      necessidade_bruta: nums[nums.length - 2],
      necessidade: nums[nums.length - 1]
    });
  }
} else {
  rows = items.map((i) => i.json).filter((o) => o && Object.keys(o).length);
}
return [{ json: {
  label: (meta.label || '').toString().trim() || 'Relatório de Necessidades',
  competencia,
  userId: (meta.userId || '').toString().trim() || null,
  total_linhas: rows.length,
  rows
} }];
